{"content": "     1|// ── Content Resolvers ──
     2|// @ai-whisperers/content is NOT published on npm (E404).
     3|// These functions were previously re-exported from it.
     4|// They are now resolved inline — the package contained just 4 re-export functions.
     5|// TODO: Replace with proper implementations or publish @ai-whisperers/content.
     6|
     7|import { readFileSync, existsSync } from 'fs'
     8|import { join } from 'path'
     9|
    10|const REPO = process.cwd()
    11|
    12|function loadJson<T>(...pathSegments: string[]): T | null {
    13|  try {
    14|    return JSON.parse(readFileSync(join(REPO, ...pathSegments), 'utf-8'))
    15|  } catch {
    16|    return null
    17|  }
    18|}
    19|
    20|export function resolveContent(locale: string, key: string): any {
    21|  const content = loadJson<Record<string, any>>('content', `${locale}.json`)
    22|  if (!content) return null
    23|  const parts = key.split('.')
    24|  let current: any = content
    25|  for (const part of parts) {
    26|    if (current?.[part] !== undefined) current = current[part]
    27|    else return null
    28|  }
    29|  return current
    30|}
    31|
    32|export function resolveImage(images: any, ref: string | undefined): string {
    33|  if (!ref || !images) return ''
    34|  const key = ref.replace('@img:', '').replace('@src:', '')
    35|  const parts = key.split('.')
    36|  let obj: any = images
    37|  for (const p of parts) {
    38|    if (obj?.[p]) obj = obj[p]
    39|    else return ''
    40|  }
    41|  return obj?.src || obj || ''
    42|}
    43|
    44|export function resolveConfig(key: string): any {
    45|  const site = loadJson<any>('site.json')
    46|  if (!site) return null
    47|  const parts = key.split('.')
    48|  let current: any = site
    49|  for (const part of parts) {
    50|    if (current?.[part] !== undefined) current = current[part]
    51|    else return null
    52|  }
    53|  return current
    54|}
    55|
    56|export function localizedField(obj: any, locale: string): string {
    57|  if (!obj) return ''
    58|  if (typeof obj === 'string') return obj
    59|  if (typeof obj === 'object' && obj[locale]) return obj[locale]
    60|  // fallback chain: nl > en > any
    61|  const fallbacks = ['nl', 'en', 'de', 'es']
    62|  for (const fb of fallbacks) {
    63|    if (obj[fb]) return obj[fb]
    64|  }
    65|  return Object.values(obj)[0] as string || ''
    66|}
