{"content": "// ─── Site Content — Universal Supabase + File Fallback Loader ───────────────
// Works for ALL Ai-Whisperers clients. Uses Supabase site_content table,
// falls back to local JSON files if Supabase is unreachable.

export interface ContentLoaderConfig {
  tenantSlug: string
  locales: string[]
  defaultLocale: string
  contentDir: string        // path to content/ directory for file fallback
  supabaseUrl?: string
  supabaseAnonKey?: string
  useDb?: boolean           // set true to try Supabase first
  cacheTTL?: number         // cache TTL in ms, default [REDACTED_PHONE]s)
}

export interface LoadedContent {
  [key: string]: any
}

interface CacheEntry {
  data: LoadedContent
  timestamp: number
}

// In-memory cache (per-tenant, per-locale)
const cache = new Map<string, CacheEntry>()

function cacheKey(tenant: string, locale: string): string {
  return `${tenant}:${locale}`
}

function getCached(tenant: string, locale: string): LoadedContent | null {
  const entry = cache.get(cacheKey(tenant, locale))
  if (!entry) return null
  return entry.data
}

function setCache(tenant: string, locale: string, data: LoadedContent, ttl: number): void {
  cache.set(cacheKey(tenant, locale), { data, timestamp: Date.now() + ttl })
}

function isFresh(key: string): boolean {
  const entry = cache.get(key)
  return !!entry && Date.now() < entry.timestamp
}

// ─── Load from Supabase ─────────────────────────────────────────────────────

async function loadFromSupabase(
  config: ContentLoaderConfig,
  locale: string
): Promise<LoadedContent | null> {
  if (!config.supabaseUrl || !config.supabaseAnonKey) return null

  try {
    const { createClient } = await import('@supabase/supabase-js')
    const supabase = createClient(config.supabaseUrl, config.supabaseAnonKey)

    // Fetch ALL rows for this tenant + locale
    const { data, error } = await supabase
      .from('site_content')
      .select('key_path, content')
      .eq('tenant_slug', config.tenantSlug)
      .eq('locale', locale)

    if (error) {
      console.warn(`[content-loader] Supabase error for ${config.tenantSlug}/${locale}:`, error.message)
      return null
    }

    if (!data || data.length === 0) return null

    // Reconstruct nested object from flat key_paths
    // e.g. key_path = "home.hero.headline", content = "Hello" => { home: { hero: { headline: "Hello" } } }
    const result: LoadedContent = {}
    for (const row of data) {
      const keys = row.key_path.split('.')
      let current = result
      for (let i = 0; i < keys.length; i++) {
        const k = keys[i]
        if (i === keys.length - 1) {
          current[k] = row.content
        } else {
          current[k] = current[k] || {}
          current = current[k]
        }
      }
    }

    return result
  } catch (err) {
    console.warn(`[content-loader] Supabase connection failed for ${config.tenantSlug}:`, err)
    return null
  }
}

// ─── Load from JSON files (fallback) ────────────────────────────────────────

function loadFromFile(config: ContentLoaderConfig, locale: string): LoadedContent | null {
  try {
    // Use dynamic import for fs — works in Next.js server components
    // In browser context, this fallback won't work, but Supabase should
    const fs = require('fs')
    const path = require('path')
    const filePath = path.join(config.contentDir, `${locale}.json`)
    if (!fs.existsSync(filePath)) return null
    const raw = fs.readFileSync(filePath, 'utf-8')
    return JSON.parse(raw)
  } catch {
    return null
  }
}

// ─── Main Loader ────────────────────────────────────────────────────────────

export async function loadContent(
  config: ContentLoaderConfig,
  locale?: string
): Promise<LoadedContent> {
  const loc = locale || config.defaultLocale

  // Check cache first
  const ck = cacheKey(config.tenantSlug, loc)
  if (isFresh(ck)) {
    return getCached(config.tenantSlug, loc)!
  }

  let data: LoadedContent | null = null

  // Try Supabase first if enabled
  if (config.useDb) {
    data = await loadFromSupabase(config, loc)
  }

  // Fallback to files
  if (!data) {
    data = loadFromFile(config, loc)
  }

  // Last resort: empty object
  if (!data) {
    console.warn(`[content-loader] No content found for ${config.tenantSlug}/${loc}`)
    data = {}
  }

  // Cache and return
  const ttl = config.cacheTTL || 30000
  setCache(config.tenantSlug, loc, data!, ttl)
  return data!
}

// ─── Cache Invalidation ────────────────────────────────────────────────────

export function invalidateCache(tenant?: string, locale?: string): void {
  if (tenant && locale) {
    cache.delete(cacheKey(tenant, locale))
  } else if (tenant) {
    for (const key of cache.keys()) {
      if (key.startsWith(tenant + ':')) cache.delete(key)
    }
  } else {
    cache.clear()
  }
}

// ─── Migration Helper: Flatten nested object to key_path rows ───────────────

export function flattenToKeyPaths(
  obj: any,
  prefix = ''
): Array<{ key_path: string; content: any }> {
  const result: Array<{ key_path: string; content: any }> = []

  for (const [key, value] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${key}` : key

    if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
      // Recurse into objects
      result.push(...flattenToKeyPaths(value, path))
    } else {
      // Leaf value
      result.push({ key_path: path, content: value })
    }
  }

  return result
}

// ─── Batch Insert to Supabase ──────────────────────────────────────────────

export async function migrateContentToSupabase(
  config: ContentLoaderConfig,
  supabaseServiceKey: string
): Promise<{ inserted: number; errors: string[] }> {
  const { createClient } = await import('@supabase/supabase-js')
  if (!config.supabaseUrl) return { inserted: 0, errors: ['No Supabase URL'] }

  const supabase = createClient(config.supabaseUrl, supabaseServiceKey)
  let inserted = 0
  const errors: string[] = []

  for (const locale of config.locales) {
    const fileData = loadFromFile(config, locale)
    if (!fileData) {
      errors.push(`No file found for ${locale}`)
      continue
    }

    const rows = flattenToKeyPaths(fileData).map(r => ({
      tenant_slug: config.tenantSlug,
      locale,
      key_path: r.key_path,
      content: r.content,
    }))

    // Upsert in batches of 100
    for (let i = 0; i < rows.length; i += 100) {
      const batch = rows.slice(i, i + 100)
      const { error } = await supabase
        .from('site_content')
        .upsert(batch, { onConflict: 'tenant_slug,locale,key_path', ignoreDuplicates: false })

      if (error) {
        errors.push(`Batch ${i}: ${error.message}`)
      } else {
        inserted += batch.length
      }
    }
  }

  return { inserted, errors }
}

// ─── ISR Revalidation Helper ────────────────────────────────────────────────

export function revalidateContent(tenant: string, locale?: string): void {
  invalidateCache(tenant, locale)
  // If running in Next.js, trigger ISR revalidation
  if (typeof fetch !== 'undefined') {
    const revalidateUrl = process.env.NEXT_PUBLIC_APP_URL
    if (revalidateUrl) {
      fetch(`${revalidateUrl}/api/revalidate?tenant=${tenant}&locale=${locale || ''}`)
        .catch(() => {})
    }
  }
}
